import openai
openai.api_key = "INSERT YOUR API KEY"


# Replace with your model name/prompt
MODEL_NAME="gpt-3.5-turbo"
model_type = MODEL_NAME.split("-")[2]

def chatbot(query):
    result = openai.Completion.create(
        prompt=query,
        engine=model_type,
        max_tokens=64,
        n=1,
        stream=False)

    return result['choices'][0]['text']


if __name__ == '__main__':
    query = input('Enter your question: ')
    print() # empty line for aesthetic purposes
    answer = chatbot(query)
    
    print(answer.rstrip())